// // This module transfers the input 'in' to the output 'out' on the falling edge of the clock signal 'clk'. When the reset signal 'R' is high, the output 'out' is set to 0. When the reset signal 'R' is low, the output 'out' remains unchanged.
module REG32 (
	input [31:0] in,
	input clk,
	input R,
	output reg [31:0] out
);

	always @(posedge clk) begin
		if (R == 1) begin
			out <= 0;
		end
		else begin
			out <= in;
		end
	end

endmodule
